import requests

def fetch_kurdistan_news(api_key, num_articles=5):
    url = 'https://newsapi.org/v2/everything'
    params = {
        'q': 'Kurdistan Region OR Kurdish',
        'apiKey': api_key,
        'pageSize': num_articles,
        'sortBy': 'publishedAt'
    }
    response = requests.get(url, params=params)
    if response.status_code == 200:
        articles = response.json().get('articles', [])
        for idx, article in enumerate(articles, 1):
            print(f"{idx}. {article['title']} - {article['publishedAt']}")
    else:
        print('Failed to fetch news:', response.status_code)

# Example usage (requires a valid API key from NewsAPI)
# fetch_kurdistan_news('your_api_key_here')
